import { Component, OnInit } from '@angular/core';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';
import { Router } from '@angular/router';
import { AuthService } from '../../../core/services/auth.service';

@Component({
  selector: 'app-login',
  templateUrl: './login.component.html',
  styleUrls: ['./login.component.scss'],
})
export class LoginComponent implements OnInit {
  loginForm!: FormGroup;
  isLoading = false;
  errorMessage = '';
  showPassword = false;

  constructor(
    private fb: FormBuilder,
    private auth: AuthService,
    private router: Router,
  ) {}

  ngOnInit(): void {
    if (this.auth.isAuthenticated()) {
      this.router.navigate(['/dashboard']);
      return;
    }
    this.loginForm = this.fb.group({
      userId: ['', [Validators.required]],
      password: ['', [Validators.required, Validators.minLength(6)]],
      role: ['general', [Validators.required]],
    });
  }

  isInvalid(field: string): boolean {
    const c = this.loginForm.get(field);
    return !!(c?.invalid && c.touched);
  }

  togglePassword(): void {
    this.showPassword = !this.showPassword;
  }

  onSubmit(): void {
    if (this.loginForm.invalid) {
      this.loginForm.markAllAsTouched();
      return;
    }
    this.isLoading = true;
    this.errorMessage = '';
    const { userId, password, role } = this.loginForm.value as {
      userId: string;
      password: string;
      role: string;
    };
    this.auth.login({ userId, password, role }).subscribe({
      next: () => {
        this.router.navigate(['/dashboard']);
      },
      error: (err: { error?: { message?: string } }) => {
        this.isLoading = false;
        this.errorMessage =
          err.error?.message || 'Invalid credentials. Please try again.';
      },
      complete: () => {
        this.isLoading = false;
      },
    });
  }
}
<div class="login-page">
  <div class="login-bg">
    <div class="grid-overlay"></div>
    <div class="orb orb-1"></div>
    <div class="orb orb-2"></div>
    <div class="orb orb-3"></div>
  </div>

  <div class="login-card animate-fade">
    <div class="login-header">
      <div class="brand-mark">
        <svg width="36" height="36" viewBox="0 0 36 36" fill="none" xmlns="http://www.w3.org/2000/svg">
          <rect width="36" height="36" rx="10" fill="#0d9488" />
          <path d="M10 18L18 10L26 18L18 26L10 18Z" stroke="white" stroke-width="2" stroke-linejoin="round"/>
          <circle cx="18" cy="18" r="3" fill="white"/>
        </svg>
      </div>
      <div class="brand-text">
        <h1 class="brand-name">NexusPortal</h1>
        <p class="brand-tagline">Enterprise Access Management</p>
      </div>
    </div>

    <div class="login-divider">
      <span>Sign in to your account</span>
    </div>

    <form [formGroup]="loginForm" (ngSubmit)="onSubmit()" class="login-form" novalidate>
      <div class="form-group">
        <label class="form-label" for="userId">User ID</label>
        <input
          id="userId"
          type="text"
          formControlName="userId"
          class="form-control"
          placeholder="e.g. john.doe"
          autocomplete="username"
          [class.ng-invalid]="isInvalid('userId')"
          [class.ng-touched]="isInvalid('userId')"
        />
        <div *ngIf="isInvalid('userId')" class="form-error">User ID is required.</div>
      </div>

      <div class="form-group">
        <label class="form-label" for="password">Password</label>
        <div class="input-row">
          <input
            id="password"
            [type]="showPassword ? 'text' : 'password'"
            formControlName="password"
            class="form-control"
            placeholder="Enter your password"
            autocomplete="current-password"
          />
          <button type="button" class="toggle-btn" (click)="togglePassword()" tabindex="-1">
            {{ showPassword ? 'Hide' : 'Show' }}
          </button>
        </div>
        <div *ngIf="isInvalid('password')" class="form-error">Password must be at least 6 characters.</div>
      </div>

      <div class="form-group">
        <label class="form-label" for="role">Role</label>
        <select id="role" formControlName="role" class="form-control form-select">
          <option value="general">General User</option>
          <option value="admin">Admin</option>
        </select>
        <div class="form-hint">Select the role matching your account type.</div>
      </div>

      <div *ngIf="errorMessage" class="alert alert--error">
        <svg width="16" height="16" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M12 9v2m0 4h.01M10.29 3.86L1.82 18a2 2 0 001.71 3h16.94a2 2 0 001.71-3L13.71 3.86a2 2 0 00-3.42 0z"/></svg>
        {{ errorMessage }}
      </div>

      <button
        type="submit"
        class="btn btn--primary btn--full sign-in-btn"
        [class.loading]="isLoading"
        [disabled]="isLoading"
      >
        <span *ngIf="!isLoading">Sign In</span>
        <span *ngIf="isLoading" class="loading-text">
          <span class="dot-spinner"></span>Authenticating…
        </span>
      </button>
    </form>

    <div class="demo-section">
      <div class="demo-label">Demo Credentials</div>
      <div class="demo-grid">
        <div class="demo-item">
          <span class="badge badge--primary">Admin</span>
          <code class="demo-code">admin01 / Admin@123</code>
        </div>
        <div class="demo-item">
          <span class="badge badge--muted">User</span>
          <code class="demo-code">john.doe / User@123</code>
        </div>
      </div>
    </div>
  </div>
</div>
